import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapPin, ShieldCheck, Edit3, Save, X, Plus, Trash2 } from 'lucide-react';

export default function Profile() {
  const [isEditing, setIsEditing] = useState(false);
  const [userData, setUserData] = useState({
    name: "Arjun Das",
    locality: "Kadavanthra, Kochi",
    zip: "682020",
    skills: ["Web Design", "Gardening", "Plumbing", "Tutoring"]
  });
  const [newSkill, setNewSkill] = useState("");

  const handleAddSkill = (e) => {
    e.preventDefault();
    if (newSkill.trim() && !userData.skills.includes(newSkill)) {
      setUserData({ ...userData, skills: [...userData.skills, newSkill.trim()] });
      setNewSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setUserData({
      ...userData,
      skills: userData.skills.filter(skill => skill !== skillToRemove)
    });
  };

  return (
    <div className="max-w-5xl mx-auto p-8 space-y-8 pb-24">
      {/* Header Profile Card */}
      <div className="bg-white rounded-[40px] p-10 shadow-sm border border-slate-50 relative overflow-hidden">
        <div className="flex items-center gap-10">
          <div className="relative">
            <div className="w-32 h-32 bg-teal-50 rounded-full flex items-center justify-center text-teal-600 border-4 border-white shadow-xl">
              <span className="text-4xl font-black">{userData.name.charAt(0)}</span>
            </div>
            <div className="absolute bottom-2 right-2 w-6 h-6 bg-green-500 border-4 border-white rounded-full"></div>
          </div>

          <div className="flex-1">
            {isEditing ? (
              <input 
                value={userData.name}
                onChange={(e) => setUserData({...userData, name: e.target.value})}
                className="text-4xl font-black text-slate-900 bg-slate-50 px-4 py-2 rounded-2xl outline-none ring-2 ring-teal-500 w-full max-w-md"
              />
            ) : (
              <h1 className="text-4xl font-black text-slate-900">{userData.name}</h1>
            )}
            <div className="flex items-center gap-2 text-slate-400 font-bold mt-2">
              <MapPin size={18} className="text-teal-500" /> {userData.locality}
            </div>
            <div className="mt-4 inline-flex items-center gap-2 px-4 py-1.5 bg-teal-50 text-teal-600 rounded-full text-[10px] font-black uppercase tracking-widest">
              <ShieldCheck size={14} /> Verified Member
            </div>
          </div>

          <button 
            onClick={() => setIsEditing(!isEditing)}
            className={`flex items-center gap-2 px-8 py-4 rounded-2xl font-bold transition-all ${isEditing ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-600'}`}
          >
            {isEditing ? <><Save size={20} /> Save Profile</> : <><Edit3 size={20} /> Edit Profile</>}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {/* Skills Section */}
        <div className="md:col-span-2 bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm">
          <h3 className="text-xl font-black text-slate-900 mb-8">Skills & Exchange Preferences</h3>
          
          <div className="flex flex-wrap gap-3 mb-10">
            {userData.skills.map((skill) => (
              <motion.div 
                layout
                key={skill}
                className="flex items-center gap-2 px-6 py-3 bg-teal-50 text-teal-700 rounded-2xl font-bold text-sm border border-teal-100 group"
              >
                {skill}
                {isEditing && (
                  <button onClick={() => removeSkill(skill)} className="text-teal-300 hover:text-red-500 transition-colors">
                    <Trash2 size={16} />
                  </button>
                )}
              </motion.div>
            ))}
          </div>

          <AnimatePresence>
            {isEditing && (
              <motion.form 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                onSubmit={handleAddSkill} 
                className="flex gap-4"
              >
                <input 
                  value={newSkill}
                  onChange={(e) => setNewSkill(e.target.value)}
                  placeholder="Add a new skill (e.g. Yoga, Painting)..."
                  className="flex-1 bg-slate-50 px-6 py-4 rounded-2xl border-none outline-none ring-2 ring-transparent focus:ring-teal-500 transition-all font-medium"
                />
                <button type="submit" className="bg-teal-600 text-white p-4 rounded-2xl hover:bg-teal-700 shadow-lg shadow-teal-600/20">
                  <Plus size={24} />
                </button>
              </motion.form>
            )}
          </AnimatePresence>
        </div>

        {/* Locality Section (Static based on image) */}
        <div className="bg-slate-900 text-white rounded-[40px] p-10 shadow-2xl">
          <h3 className="text-xl font-black mb-6 flex items-center gap-2">
             Locality & Reach
          </h3>
          <div className="space-y-6 opacity-80">
            <div>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Current Locality</p>
              <p className="font-bold">{userData.locality}</p>
            </div>
            <div>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Zip Code</p>
              <p className="font-bold">{userData.zip}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
